     1→/**
     2→ * Multi-Label Selection Stage
     3→ *
     4→ * Implements sophisticated multi-label selection logic based on ranking algorithms,
     5→ * confidence thresholds, co-presence rules, and AI routing decisions.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Ranking categories by final scores
     9→ * - Selecting primary and secondary labels based on confidence and gap thresholds
    10→ * - Enforcing co-presence rules and allowed combinations
    11→ * - Determining AI classification requirements
    12→ * - Generating complete selection rationale and audit trails
    13→ */
    14→
    15→import {
    16→  CategoryScore,
    17→  MultiLabelConfig,
    18→  ConfidenceThresholds,
    19→  SelectedLabel,
    20→  SelectionSummary,
    21→  MultiLabelSelectionResult,
    22→} from './types';
    23→import { ClassificationSession } from '../types/classification-session';
    24→import { ClassificationResult } from '../types/classification-result';
    25→import { EmailMessage } from '../types/email-message';
    26→
    27→/**
    28→ * Execute multi-label selection stage (canonical signature)
    29→ *
    30→ * Ranks categories, selects primary/secondary labels, and determines AI routing needs.
    31→ *
    32→ * Mutates the result object in place by setting primaryCategory, secondaryCategories,
    33→ * and updating explainability trace with selection decisions.
    34→ */
    35→// FIXME some parameters appear unused - should these just be documented as common interface parameters?
    36→export function executeMultiLabelSelection(
    37→  email: EmailMessage,
    38→  session: ClassificationSession,
    39→  result: ClassificationResult,
    40→  config: MultiLabelConfig,
    41→  thresholds: ConfidenceThresholds
    42→): void {
    43→  const startTime = Date.now();
    44→
    45→  // Validate configuration
    46→  validateConfiguration(config, thresholds);
    47→
    48→  // Extract candidate scores from result.scoreBreakdown
    49→  const candidateScores: Record<string, CategoryScore> = {};
    50→  for (const [category, scoreData] of Object.entries(result.scoreBreakdown.categoryScores)) {
    51→    candidateScores[category] = {
    52→      score: scoreData.finalScore || scoreData.baseScore || 0,
    53→      confidence: scoreData.finalScore || scoreData.baseScore || 0,
    54→      rationale: '',
    55→      decision: undefined,
    56→    };
    57→  }
    58→
    59→  // Rank categories by score
    60→  const rankedCategories = rankCategoriesByScore(candidateScores);
    61→
    62→  if (rankedCategories.length === 0) {
    63→    const duration = Date.now() - startTime;
    64→    result.processingDurationMs += duration;
    65→    result.explainabilityTrace.stageTimings['multi_label_selection'] = duration;
    66→    result.explainabilityTrace.configurationRefs['multi_label_selection'] = 'settings.multi_label_selection';
    67→    result.explainabilityTrace.multiLabelSelection = [];
    68→    return;
    69→  }
    70→
    71→  const selectedLabels: SelectedLabel[] = [];
    72→
    73→  // Select primary label
    74→  const primaryCandidate = rankedCategories[0];
    75→  if (primaryCandidate.score >= thresholds.lowConfidence) {
    76→    const primaryLabel: SelectedLabel = {
    77→      category: primaryCandidate.category,
    78→      subtype: primaryCandidate.selectedSubtypeId || null,
    79→      confidence: primaryCandidate.confidence,
    80→      score: primaryCandidate.score,
    81→      isPrimary: true,
    82→      labelOrder: 1,
    83→      selectionRationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${thresholds.lowConfidence})`,
    84→    };
    85→    selectedLabels.push(primaryLabel);
    86→
    87→    // Select secondary labels
    88→    selectSecondaryLabels(rankedCategories, selectedLabels, primaryCandidate, config, thresholds);
    89→  }
    90→
    91→  // Update category decisions
    92→  updateCategoryDecisions(candidateScores, selectedLabels, thresholds);
    93→
    94→  // Determine AI classification need
    95→  const needsAiClassification = determineAiClassificationNeed(selectedLabels, thresholds);
    96→
    97→  const duration = Date.now() - startTime;
    98→
    99→  // Mutate result: Update primary and secondary categories
   100→  if (selectedLabels.length > 0) {
   101→    const primaryLabel = selectedLabels.find((l) => l.isPrimary) || selectedLabels[0];
   102→    result.primaryCategory = primaryLabel.category;
   103→    result.secondaryCategories = selectedLabels.filter((l) => !l.isPrimary).map((l) => l.category);
   104→    result.confidence = primaryLabel.confidence / 100; // Normalize to 0-1
   105→  }
   106→
   107→  // Update AI routing flag
   108→  result.aiRoutingUsed = needsAiClassification;
   109→
   110→  // Update result processing duration
   111→  result.processingDurationMs += duration;
   112→
   113→  // Add parallel stage result tracking
   114→  result.parallelStageResults.push({
   115→    stageId: `multi_label_selection_${result.id}`,
   116→    stageName: 'multi_label_selection',
   117→    executionTimeMs: duration,
   118→    parallelWithStages: [],
   119→    dependentOnStages: ['disambiguation'],
   120→    cacheHitsCount: 0,
   121→    errorCount: 0,
   122→  });
   123→
   124→  // Update explainability trace (convert to ExplainabilityTrace.MultiLabelResult format)
   125→  const multiLabelResults: Array<{
   126→    selectedCategories: string[];
   127→    rejectedCategories: Array<{
   128→      category: string;
   129→      score: number;
   130→      rejectionReason: string;
   131→    }>;
   132→    coPresenceRulesApplied: string[];
   133→    maxLabelsLimit: number;
   134→    minSecondaryConfidence: number;
   135→    reason: string;
   136→  }> = [
   137→    {
   138→      selectedCategories: selectedLabels.map((l) => l.category),
   139→      rejectedCategories: rankedCategories
   140→        .filter((cat) => !selectedLabels.some((l) => l.category === cat.category))
   141→        .map((cat) => ({
   142→          category: cat.category,
   143→          score: cat.score,
   144→          rejectionReason:
   145→            cat.score < thresholds.lowConfidence
   146→              ? `Below minimum threshold (${cat.score} < ${thresholds.lowConfidence})`
   147→              : 'Exceeded max labels limit or failed combination rules',
   148→        })),
   149→      coPresenceRulesApplied: [], // Populated based on allowed combinations
   150→      maxLabelsLimit: config.maxLabels,
   151→      minSecondaryConfidence: config.minSecondaryConfidence,
   152→      reason:
   153→        selectedLabels.length > 0
   154→          ? `Selected ${selectedLabels.length} labels with primary: ${selectedLabels.find((l) => l.isPrimary)?.category || selectedLabels[0].category}`
   155→          : 'No labels met minimum confidence threshold',
   156→    },
   157→  ];
   158→
   159→  result.explainabilityTrace.multiLabelSelection = multiLabelResults;
   160→  result.explainabilityTrace.stageTimings['multi_label_selection'] = duration;
   161→  result.explainabilityTrace.configurationRefs['multi_label_selection'] = 'settings.multi_label_selection';
   162→}
   163→
   164→/**
   165→ * Validate configuration parameters
   166→ */
   167→function validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
   168→  if (config.maxLabels < 0) {
   169→    throw new Error('Invalid configuration: maxLabels cannot be negative');
   170→  }
   171→
   172→  if (config.minSecondaryConfidence < 0) {
   173→    throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
   174→  }
   175→
   176→  if (thresholds.highConfidence <= thresholds.mediumConfidence) {
   177→    throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
   178→  }
   179→
   180→  if (thresholds.mediumConfidence <= thresholds.lowConfidence) {
   181→    throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
   182→  }
   183→
   184→  if (thresholds.secondaryLabelMinGap < 0) {
   185→    throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
   186→  }
   187→}
   188→
   189→/**
   190→ * Rank categories by score in descending order, filtering out zero/negative scores
   191→ */
   192→function rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
   193→  category: string;
   194→  score: number;
   195→  confidence: number;
   196→  rationale: string;
   197→  selectedSubtypeId?: string | null;
   198→}> {
   199→  return Object.entries(candidateScores)
   200→    .map(([category, scoreData]) => ({
   201→      category,
   202→      score: scoreData.score || 0,
   203→      confidence: scoreData.confidence || 0,
   204→      rationale: scoreData.rationale || '',
   205→      selectedSubtypeId: scoreData.selectedSubtypeId,
   206→    }))
   207→    .filter((item) => item.score > 0)
   208→    .sort((a, b) => {
   209→      // Primary sort by score (descending)
   210→      if (b.score !== a.score) {
   211→        return b.score - a.score;
   212→      }
   213→      // Secondary sort by category name for stable ordering
   214→      return a.category.localeCompare(b.category);
   215→    });
   216→}
   217→
   218→/**
   219→ * Select secondary labels within gap threshold and above minimum confidence
   220→ */
   221→function selectSecondaryLabels(
   222→  rankedCategories: Array<{
   223→    category: string;
   224→    score: number;
   225→    confidence: number;
   226→    rationale: string;
   227→    selectedSubtypeId?: string | null;
   228→  }>,
   229→  selectedLabels: SelectedLabel[],
   230→  primaryCandidate: {
   231→    category: string;
   232→    score: number;
   233→    confidence: number;
   234→    rationale: string;
   235→    selectedSubtypeId?: string | null;
   236→  },
   237→  config: MultiLabelConfig,
   238→  thresholds: ConfidenceThresholds
   239→): void {
   240→  if (config.maxLabels <= 1 || rankedCategories.length <= 1) {
   241→    return;
   242→  }
   243→
   244→  const primaryScore = primaryCandidate.score;
   245→
   246→  for (let i = 1; i < rankedCategories.length && selectedLabels.length < config.maxLabels; i++) {
   247→    const candidate = rankedCategories[i];
   248→    const scoreDifference = primaryScore - candidate.score;
   249→
   250→    // Check if candidate meets secondary label criteria
   251→    if (candidate.score >= config.minSecondaryConfidence && scoreDifference <= thresholds.secondaryLabelMinGap) {
   252→      // Check if combination is allowed
   253→      if (isCombinationAllowed(primaryCandidate.category, candidate.category, config)) {
   254→        const secondaryLabel: SelectedLabel = {
   255→          category: candidate.category,
   256→          subtype: candidate.selectedSubtypeId || null,
   257→          confidence: candidate.confidence,
   258→          score: candidate.score,
   259→          isPrimary: false,
   260→          labelOrder: selectedLabels.length + 1,
   261→          selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${thresholds.secondaryLabelMinGap}) and above minimum confidence (${config.minSecondaryConfidence})`,
   262→        };
   263→        selectedLabels.push(secondaryLabel);
   264→      }
   265→    }
   266→  }
   267→}
   268→
   269→/**
   270→ * Check if category combination is allowed based on configuration
   271→ */
   272→function isCombinationAllowed(primaryCategory: string, candidateCategory: string, config: MultiLabelConfig): boolean {
   273→  if (primaryCategory === candidateCategory) {
   274→    return true;
   275→  }
   276→
   277→  // If strict mode is enabled and combinations are specified, only allow explicit combinations
   278→  if (config.strictCombinationMode && config.allowedCombinations.length > 0) {
   279→    const combination1 = `${primaryCategory}+${candidateCategory}`;
   280→    const combination2 = `${candidateCategory}+${primaryCategory}`;
   281→    return config.allowedCombinations.includes(combination1) || config.allowedCombinations.includes(combination2);
   282→  }
   283→
   284→  // If no combinations specified, allow all (default permissive mode)
   285→  if (config.allowedCombinations.length === 0) {
   286→    return true;
   287→  }
   288→
   289→  // If combinations are specified but not in strict mode, still check them
   290→  const combination1 = `${primaryCategory}+${candidateCategory}`;
   291→  const combination2 = `${candidateCategory}+${primaryCategory}`;
   292→  const isExplicitlyAllowed =
   293→    config.allowedCombinations.includes(combination1) || config.allowedCombinations.includes(combination2);
   294→
   295→  // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   296→  return isExplicitlyAllowed || !config.strictCombinationMode;
   297→}
   298→
   299→/**
   300→ * Update category decisions based on selection results
   301→ */
   302→function updateCategoryDecisions(
   303→  candidateScores: Record<string, CategoryScore>,
   304→  selectedLabels: SelectedLabel[],
   305→  thresholds: ConfidenceThresholds
   306→): void {
   307→  const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));
   308→
   309→  for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
   310→    const score = scoreData.score || 0;
   311→
   312→    if (selectedCategoryNames.has(categoryCode)) {
   313→      // Selected categories get decision based on confidence
   314→      if (score >= thresholds.highConfidence) {
   315→        scoreData.decision = 'positive';
   316→        scoreData.decisionRationale = `High confidence (${score} >= ${thresholds.highConfidence}) - finalized without AI`;
   317→      } else if (score >= thresholds.mediumConfidence) {
   318→        scoreData.decision = 'candidate';
   319→        scoreData.decisionRationale = `Medium confidence (${score} >= ${thresholds.mediumConfidence}) - may need AI validation`;
   320→      } else {
   321→        scoreData.decision = 'candidate';
   322→        scoreData.decisionRationale = `Low confidence (${score} >= ${thresholds.lowConfidence}) - needs AI classification`;
   323→      }
   324→    } else {
   325→      // Non-selected categories are rejected
   326→      scoreData.decision = 'rejected';
   327→      if (score < thresholds.lowConfidence) {
   328→        scoreData.decisionRationale = `Below minimum threshold (${score} < ${thresholds.lowConfidence})`;
   329→      } else {
   330→        scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
   331→      }
   332→    }
   333→  }
   334→}
   335→
   336→/**
   337→ * Determine if AI classification is needed based on selected labels
   338→ */
   339→function determineAiClassificationNeed(selectedLabels: SelectedLabel[], thresholds: ConfidenceThresholds): boolean {
   340→  if (selectedLabels.length === 0) {
   341→    return true; // No labels selected - need AI
   342→  }
   343→
   344→  // Check if primary label has high confidence (can skip AI)
   345→  const primaryLabel = selectedLabels.find((label) => label.isPrimary);
   346→  if (primaryLabel && primaryLabel.score >= thresholds.highConfidence) {
   347→    return false; // High confidence primary - skip AI
   348→  }
   349→
   350→  // Check if any label is below medium confidence (needs AI)
   351→  const hasLowConfidenceLabel = selectedLabels.some((label) => label.score < thresholds.mediumConfidence);
   352→  if (hasLowConfidenceLabel) {
   353→    return true; // Has low confidence labels - need AI
   354→  }
   355→
   356→  // Conservative approach for medium confidence range
   357→  return true;
   358→}
