   361→/**
   362→ * @deprecated Legacy class-based interface - use executeMultiLabelSelection function instead
   363→ */
   364→export class MultiLabelSelectionStage {
   365→  private config: MultiLabelConfig;
   366→  private thresholds: ConfidenceThresholds;
   367→
   368→  constructor(config: MultiLabelConfig, thresholds: ConfidenceThresholds) {
   369→    this.validateConfiguration(config, thresholds);
   370→    this.config = config;
   371→    this.thresholds = thresholds;
   372→  }
   373→
   374→  /**
   375→   * Validate configuration parameters
   376→   */
   377→  private validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
   378→    if (config.maxLabels < 0) {
   379→      throw new Error('Invalid configuration: maxLabels cannot be negative');
   380→    }
   381→
   382→    if (config.minSecondaryConfidence < 0) {
   383→      throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
   384→    }
   385→
   386→    if (thresholds.highConfidence <= thresholds.mediumConfidence) {
   387→      throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
   388→    }
   389→
   390→    if (thresholds.mediumConfidence <= thresholds.lowConfidence) {
   391→      throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
   392→    }
   393→
   394→    if (thresholds.secondaryLabelMinGap < 0) {
   395→      throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
   396→    }
   397→  }
   398→
   399→  /**
   400→   * Rank categories by score in descending order, filtering out zero/negative scores
   401→   */
   402→  public rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
   403→    category: string;
   404→    score: number;
   405→    confidence: number;
   406→    rationale: string;
   407→    selectedSubtypeId?: string | null;
   408→  }> {
   409→    return Object.entries(candidateScores)
   410→      .map(([category, scoreData]) => ({
   411→        category,
   412→        score: scoreData.score || 0,
   413→        confidence: scoreData.confidence || 0,
   414→        rationale: scoreData.rationale || '',
   415→        selectedSubtypeId: scoreData.selectedSubtypeId,
   416→      }))
   417→      .filter((item) => item.score > 0)
   418→      .sort((a, b) => {
   419→        // Primary sort by score (descending)
   420→        if (b.score !== a.score) {
   421→          return b.score - a.score;
   422→        }
   423→        // Secondary sort by category name for stable ordering
   424→        return a.category.localeCompare(b.category);
   425→      });
   426→  }
   427→
   428→  /**
   429→   * Main selection logic: select labels based on multi-label selection rules
   430→   */
   431→  public selectLabels(candidateScores: Record<string, CategoryScore>): MultiLabelSelectionResult {
   432→    const startTime = Date.now();
   433→
   434→    // Rank categories by score
   435→    const rankedCategories = this.rankCategoriesByScore(candidateScores);
   436→
   437→    if (rankedCategories.length === 0) {
   438→      return this.createNoSelectionResult(startTime);
   439→    }
   440→
   441→    const selectedLabels: SelectedLabel[] = [];
   442→
   443→    // Select primary label
   444→    const primaryCandidate = rankedCategories[0];
   445→    if (primaryCandidate.score >= this.thresholds.lowConfidence) {
   446→      const primaryLabel: SelectedLabel = {
   447→        category: primaryCandidate.category,
   448→        subtype: primaryCandidate.selectedSubtypeId || null,
   449→        confidence: primaryCandidate.confidence,
   450→        score: primaryCandidate.score,
   451→        isPrimary: true,
   452→        labelOrder: 1,
   453→        selectionRationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${this.thresholds.lowConfidence})`,
   454→      };
   455→      selectedLabels.push(primaryLabel);
   456→    } else {
   457→      return this.createNoSelectionResult(startTime);
   458→    }
   459→
   460→    // Select secondary labels
   461→    this.selectSecondaryLabels(rankedCategories, selectedLabels, primaryCandidate);
   462→
   463→    // Update category decisions
   464→    this.updateCategoryDecisions(candidateScores, selectedLabels);
   465→
   466→    // Determine AI classification need
   467→    const needsAiClassification = this.determineAiClassificationNeed(selectedLabels);
   468→
   469→    // Create selection summary
   470→    const selectionSummary = this.createSelectionSummary(selectedLabels, rankedCategories, needsAiClassification);
   471→
   472→    return {
   473→      selectedLabels,
   474→      needsAiClassification,
   475→      selectionSummary,
   476→      processingDurationMs: Date.now() - startTime,
   477→    };
   478→  }
   479→
   480→  /**
   481→   * Select secondary labels within gap threshold and above minimum confidence
   482→   */
   483→  private selectSecondaryLabels(
   484→    rankedCategories: Array<{
   485→      category: string;
   486→      score: number;
   487→      confidence: number;
   488→      rationale: string;
   489→      selectedSubtypeId?: string | null;
   490→    }>,
   491→    selectedLabels: SelectedLabel[],
   492→    primaryCandidate: {
   493→      category: string;
   494→      score: number;
   495→      confidence: number;
   496→      rationale: string;
   497→      selectedSubtypeId?: string | null;
   498→    }
   499→  ): void {
   500→    if (this.config.maxLabels <= 1 || rankedCategories.length <= 1) {
   501→      return;
   502→    }
   503→
   504→    const primaryScore = primaryCandidate.score;
   505→
   506→    for (let i = 1; i < rankedCategories.length && selectedLabels.length < this.config.maxLabels; i++) {
   507→      const candidate = rankedCategories[i];
   508→      const scoreDifference = primaryScore - candidate.score;
   509→
   510→      // Check if candidate meets secondary label criteria
   511→      if (
   512→        candidate.score >= this.config.minSecondaryConfidence &&
   513→        scoreDifference <= this.thresholds.secondaryLabelMinGap
   514→      ) {
   515→        // Check if combination is allowed
   516→        if (this.isCombinationAllowed(primaryCandidate.category, candidate.category)) {
   517→          const secondaryLabel: SelectedLabel = {
   518→            category: candidate.category,
   519→            subtype: candidate.selectedSubtypeId || null,
   520→            confidence: candidate.confidence,
   521→            score: candidate.score,
   522→            isPrimary: false,
   523→            labelOrder: selectedLabels.length + 1,
   524→            selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${this.thresholds.secondaryLabelMinGap}) and above minimum confidence (${this.config.minSecondaryConfidence})`,
   525→          };
   526→          selectedLabels.push(secondaryLabel);
   527→        }
   528→      }
   529→    }
   530→  }
   531→
   532→  /**
   533→   * Check if category combination is allowed based on configuration
   534→   */
   535→  private isCombinationAllowed(primaryCategory: string, candidateCategory: string): boolean {
   536→    if (primaryCategory === candidateCategory) {
   537→      return true;
   538→    }
   539→
   540→    // If strict mode is enabled and combinations are specified, only allow explicit combinations
   541→    if (this.config.strictCombinationMode && this.config.allowedCombinations.length > 0) {
   542→      const combination1 = `${primaryCategory}+${candidateCategory}`;
   543→      const combination2 = `${candidateCategory}+${primaryCategory}`;
   544→      return (
   545→        this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2)
   546→      );
   547→    }
   548→
   549→    // If no combinations specified, allow all (default permissive mode)
   550→    if (this.config.allowedCombinations.length === 0) {
   551→      return true;
   552→    }
   553→
   554→    // If combinations are specified but not in strict mode, still check them (current config has financial+actionable)
   555→    const combination1 = `${primaryCategory}+${candidateCategory}`;
   556→    const combination2 = `${candidateCategory}+${primaryCategory}`;
   557→    const isExplicitlyAllowed =
   558→      this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2);
   559→
   560→    // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   561→    return isExplicitlyAllowed || !this.config.strictCombinationMode;
   562→  }
   563→
   564→  /**
   565→   * Update category decisions based on selection results
   566→   */
   567→  private updateCategoryDecisions(
   568→    candidateScores: Record<string, CategoryScore>,
   569→    selectedLabels: SelectedLabel[]
   570→  ): void {
   571→    const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));
   572→
   573→    for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
   574→      const score = scoreData.score || 0;
   575→
   576→      if (selectedCategoryNames.has(categoryCode)) {
   577→        // Selected categories get decision based on confidence
   578→        if (score >= this.thresholds.highConfidence) {
   579→          scoreData.decision = 'positive';
   580→          scoreData.decisionRationale = `High confidence (${score} >= ${this.thresholds.highConfidence}) - finalized without AI`;
   581→        } else if (score >= this.thresholds.mediumConfidence) {
   582→          scoreData.decision = 'candidate';
   583→          scoreData.decisionRationale = `Medium confidence (${score} >= ${this.thresholds.mediumConfidence}) - may need AI validation`;
   584→        } else {
   585→          scoreData.decision = 'candidate';
   586→          scoreData.decisionRationale = `Low confidence (${score} >= ${this.thresholds.lowConfidence}) - needs AI classification`;
   587→        }
   588→      } else {
   589→        // Non-selected categories are rejected
   590→        scoreData.decision = 'rejected';
   591→        if (score < this.thresholds.lowConfidence) {
   592→          scoreData.decisionRationale = `Below minimum threshold (${score} < ${this.thresholds.lowConfidence})`;
   593→        } else {
