     5→/**
     6→ * Rule-Based Scoring Stage
     7→ *
     8→ * Implements lexical pattern matching per SCORING_LOGIC.md "Subtype Scoring Formula" section.
     9→ * Applies rule-based classification patterns with bounded aggregation to prevent score inflation
    10→ * while allowing multiple patterns to contribute to category confidence.
    11→ *
    12→ * CANONICAL SIGNATURE: (email, session, result, config) => void
    13→ *
    14→ * Logic:
    15→ * - score(subtype) = sum(top_k(high_matches, K_high))
    16→ *                  + M_medium * sum(top_k(medium_matches, K_medium))
    17→ *                  + M_low * sum(top_k(low_matches, K_low))
    18→ *                  + attribute_bonus(subtype)
    19→ * - Category score = primary + min(secondary_support, secondary_support_cap)
    20→ * - Uses max of existing score vs aggregated rule score
    21→ * - Mutates result.explainabilityTrace and result.scoreBreakdown instead of returning
    22→ */
    23→
    24→export interface RulePattern {
    25→  field: string; // "subject", "body", "from.address", etc.
    26→  operation: string; // "contains_any", "starts_with", "ends_with", "regex_any", "exists"
    27→  values?: string[];
    28→  weight: number;
    29→}
    30→
    31→export interface SubtypeRuleClassification {
    32→  high_confidence?: RulePattern[];
    33→  medium_confidence?: RulePattern[];
    34→  low_confidence?: RulePattern[];
    35→}
    36→
    37→export interface SubtypeDefinition {
    38→  description: string;
    39→  rule_based_classification?: SubtypeRuleClassification;
    40→  derived?: boolean;
    41→  derivation_logic?: string;
    42→}
    43→
    44→export interface TopLevelCategory {
    45→  description: string;
    46→  subtypes: Record<string, SubtypeDefinition>;
