   152→// FIXME some parameters appear unused - should these just be documented as common interface parameters?
   153→export function executeRuleScoring(
   154→  email: EmailMessage,
   155→  session: ClassificationSession,
   156→  result: ClassificationResult,
   157→  config: RuleScoringStageConfig
   158→): void {
   159→  const startTime = Date.now();
   160→
   161→  console.log(`Rule scoring for email ${email.id}: "${email.subject?.substring(0, 50)}..."`);
   162→
   163→  const { settings, topLevelCategories, tuningParameters } = config;
   164→
   165→  // Early exit if rule scoring is disabled
   166→  if (!settings.use_lexical_patterns || !settings.apply_subtype_rules) {
   167→    console.log('Rule scoring disabled by configuration');
   168→    const durationMs = Date.now() - startTime;
   169→    result.explainabilityTrace.stageTimings['rule_scoring'] = durationMs;
   170→    result.explainabilityTrace.configurationRefs['rule_scoring'] =
   171→      'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification';
   172→    result.processingDurationMs += durationMs;
   173→    return;
   174→  }
   175→
   176→  const categoryResults: CategoryRuleResult[] = [];
   177→
   178→  console.log(`Found ${Object.keys(topLevelCategories).length} top-level categories to process`);
   179→
   180→  // Process each top-level category
   181→  for (const [categoryCode, categoryData] of Object.entries(topLevelCategories)) {
   182→    console.log(
   183→      `Processing category '${categoryCode}' with ${Object.keys(categoryData.subtypes || {}).length} subtypes`
   184→    );
   185→
   186→    const subtypeScores: Record<string, SubtypeScore> = {};
   187→    const categoryRuleMatches: RuleScoringMatch[] = [];
   188→    const categoryRationale: string[] = [];
   189→
   190→    // Process subtypes for this category
   191→    if (categoryData.subtypes) {
   192→      for (const [subtypeCode, subtypeData] of Object.entries(categoryData.subtypes)) {
   193→        const subtypeScore = scoreSubtype(email, subtypeData, subtypeCode, tuningParameters);
   194→
   195→        if (subtypeScore.totalScore > 0) {
   196→          subtypeScores[subtypeCode] = subtypeScore;
   197→          categoryRuleMatches.push(...subtypeScore.ruleMatches);
   198→          console.log(
   199→            `Subtype '${subtypeCode}' scored ${subtypeScore.totalScore} with ${subtypeScore.ruleMatches.length} matches`
   200→          );
   201→        }
   202→      }
   203→    }
   204→
   205→    // Calculate aggregated category score using bounded aggregation
   206→    let categoryScore = result.scoreBreakdown.categoryScores[categoryCode]?.finalScore || 0; // Start with existing score
   207→
   208→    if (settings.bounded_aggregation && Object.keys(subtypeScores).length > 0) {
   209→      const aggregatedScore = calculateBoundedAggregation(subtypeScores, tuningParameters);
   210→
   211→      // Use max of existing score vs aggregated rule score
   212→      categoryScore = Math.max(categoryScore, aggregatedScore.totalScore);
   213→
   214→      categoryRationale.push(`Rule aggregation: ${aggregatedScore.breakdown}`);
   215→      console.log(
   216→        `Category '${categoryCode}' rule score: ${aggregatedScore.totalScore} (${aggregatedScore.breakdown})`
   217→      );
   218→    }
   219→
   220→    // Calculate confidence based on score and number of matches
   221→    const confidence = calculateConfidence(categoryScore, categoryRuleMatches.length);
   222→
   223→    // Select best subtype
   224→    const selectedSubtypeId = selectBestSubtype(subtypeScores);
   225→
   226→    // Create category result
   227→    const categoryResult: CategoryRuleResult = {
   228→      categoryCode,
   229→      aggregatedScore: categoryScore,
   230→      subtypeScores,
   231→      ruleMatches: categoryRuleMatches,
   232→      scoringRationale:
   233→        categoryRationale.length > 0
   234→          ? categoryRationale
   235→          : [`Rule-based classification: ${categoryScore} points from ${categoryRuleMatches.length} matches`],
   236→      selectedSubtypeId,
   237→      confidence,
   238→    };
   239→
   240→    categoryResults.push(categoryResult);
   241→
