   261→    result.scoreBreakdown.categoryScores[categoryCode].finalScore = categoryScore;
   262→  }
   263→
   264→  // Calculate summary metrics
   265→  const totalMatches = categoryResults.reduce((sum, result) => sum + result.ruleMatches.length, 0);
   266→  const categoriesWithRules = categoryResults.filter((result) => Object.keys(result.subtypeScores).length > 0).length;
   267→
   268→  console.log(`Rule scoring complete - ${totalMatches} matches across ${categoriesWithRules} categories`);
   269→
   270→  // Update result.explainabilityTrace with rule scoring results
   271→  // Store CategoryRuleResult[] directly for better explainability
   272→  result.explainabilityTrace.ruleScoring = categoryResults as any;
