   274→  // Track stage timing
   275→  const durationMs = Date.now() - startTime;
   276→  result.explainabilityTrace.stageTimings['rule_scoring'] = durationMs;
   277→  result.explainabilityTrace.configurationRefs['rule_scoring'] =
