   282→/**
   283→ * Score a single subtype based on its rule-based classification patterns
   284→ */
   285→function scoreSubtype(
   286→  email: EmailMessage,
   287→  subtypeData: SubtypeDefinition,
   288→  subtypeCode: string,
   289→  tuningParams: RuleScoringStageConfig['tuningParameters']
   290→): SubtypeScore {
   291→  const subject = email.subject?.toLowerCase() || '';
   292→  const bodyText = extractEmailBodyText(email).toLowerCase();
   293→
   294→  const ruleClassification = subtypeData.rule_based_classification || {};
   295→  const matches: RuleScoringMatch[] = [];
   296→
   297→  // Process each confidence tier with bounded aggregation
   298→  const confidenceTiers: Array<{
   299→    tier: keyof SubtypeRuleClassification;
   300→    multiplier: number;
   301→    maxMatches: number;
   302→  }> = [
   303→    { tier: 'high_confidence', multiplier: 1.0, maxMatches: tuningParams.K_high },
   304→    { tier: 'medium_confidence', multiplier: tuningParams.M_medium, maxMatches: tuningParams.K_medium },
   305→    { tier: 'low_confidence', multiplier: tuningParams.M_low, maxMatches: tuningParams.K_low },
   306→  ];
   307→
   308→  let totalScore = 0;
   309→
   310→  for (const { tier, multiplier, maxMatches } of confidenceTiers) {
   311→    const tierRules = ruleClassification[tier] || [];
   312→    const tierMatches: RuleScoringMatch[] = [];
   313→
   314→    for (const rule of tierRules) {
   315→      const match = evaluateRule(rule, subject, bodyText);
   316→
   317→      if (match.matched) {
   318→        tierMatches.push({
   319→          tier,
   320→          field: rule.field,
   321→          operation: rule.operation,
   322→          values: rule.values || [],
   323→          weight: rule.weight,
   324→          matchedValue: match.matchedValue,
   325→          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
   326→          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
   327→          partialMatch: false, // For compatibility with RuleMatch base interface
   328→        });
   329→
   330→        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
   331→      }
   332→    }
   333→
   334→    // Apply bounded aggregation - take top K matches for this tier
   335→    const topMatches = tierMatches.sort((a, b) => b.weight - a.weight).slice(0, maxMatches);
   336→
   337→    // Add to total score and matches
   338→    for (const match of topMatches) {
   339→      totalScore += match.weight * multiplier;
   340→      matches.push(match);
   341→    }
   342→  }
   343→
   344→  return {
   345→    totalScore,
   346→    ruleMatches: matches,
   347→    aggregationBreakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'no_matches',
   348→  };
   349→}
   350→
   351→/**
   352→ * Evaluate a single rule against email content
   353→ */
   354→function evaluateRule(rule: RulePattern, subject: string, body: string): { matched: boolean; matchedValue: string } {
   355→  let fieldValue = '';
   356→
   357→  switch (rule.field) {
   358→  case 'subject':
   359→    fieldValue = subject;
   360→    break;
   361→  case 'body':
   362→    fieldValue = body;
   363→    break;
   364→  case 'from.address':
   365→    // This would need access to email.from, but we'll handle it in a future iteration
   366→    fieldValue = '';
   367→    break;
   368→  default:
   369→    fieldValue = '';
   370→  }
   371→
   372→  if (!fieldValue) {
   373→    return { matched: false, matchedValue: '' };
   374→  }
   375→
   376→  const values = Array.isArray(rule.values) ? rule.values : rule.values ? [rule.values] : [];
   377→
   378→  switch (rule.operation) {
   379→  case 'contains_any':
   380→    for (const value of values) {
   381→      if (fieldValue.includes(value.toLowerCase())) {
   382→        return { matched: true, matchedValue: value };
   383→      }
   384→    }
   385→    break;
   386→
   387→  case 'starts_with':
   388→    for (const value of values) {
   389→      if (fieldValue.startsWith(value.toLowerCase())) {
   390→        return { matched: true, matchedValue: value };
   391→      }
   392→    }
   393→    break;
   394→
   395→  case 'ends_with':
   396→    for (const value of values) {
   397→      if (fieldValue.endsWith(value.toLowerCase())) {
   398→        return { matched: true, matchedValue: value };
   399→      }
   400→    }
   401→    break;
   402→
   403→  case 'regex_any':
   404→    for (const pattern of values) {
   405→      try {
   406→        const regex = new RegExp(pattern, 'i');
   407→        const match = regex.exec(fieldValue);
   408→        if (match) {
   409→          return { matched: true, matchedValue: match[0] };
   410→        }
   411→      } catch (e) {
   412→        console.log(`Invalid regex pattern "${pattern}": ${e}`);
   413→      }
   414→    }
   415→    break;
   416→
   417→  case 'exists':
   418→    return { matched: fieldValue.length > 0, matchedValue: fieldValue.substring(0, 50) };
   419→
   420→  default:
   421→    console.log(`Unknown rule operation: ${rule.operation}`);
   422→  }
   423→
   424→  return { matched: false, matchedValue: '' };
   425→}
   426→
   427→/**
   428→ * Calculate bounded aggregation score to prevent inflation
   429→ * Uses diminishing returns: primary subtype + dampened tail support
   430→ */
   431→function calculateBoundedAggregation(
   432→  subtypeScores: Record<string, SubtypeScore>,
   433→  tuningParams: RuleScoringStageConfig['tuningParameters']
   434→): { totalScore: number; breakdown: string } {
   435→  const scores = Object.entries(subtypeScores)
   436→    .map(([subtype, data]) => ({ subtype, score: data.totalScore }))
   437→    .sort((a, b) => b.score - a.score); // Sort by score descending
   438→
   439→  if (scores.length === 0) {
   440→    return { totalScore: 0, breakdown: 'no_subtypes' };
   441→  }
   442→
   443→  // Primary subtype (highest score) contributes fully
   444→  const primaryScore = scores[0].score;
   445→  const primarySubtype = scores[0].subtype;
   446→
   447→  // Tail support: additional subtypes contribute with diminishing returns
   448→  let tailSupport = 0;
   449→  const tailContributions: string[] = [];
   450→
   451→  if (scores.length > 1) {
   452→    const tailScores = scores.slice(1);
   453→
   454→    for (const tail of tailScores) {
   455→      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
   456→      tailSupport += contribution;
   457→      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
   458→    }
   459→
   460→    // Apply tail ratio cap
   461→    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
   462→    tailSupport = Math.min(tailSupport, maxTailSupport);
   463→  }
   464→
   465→  const totalScore = primaryScore + tailSupport;
   466→  const breakdown =
   467→    `primary:${primarySubtype}:${primaryScore}` +
   468→    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');
   469→
   470→  return { totalScore, breakdown };
   471→}
   472→
   473→/**
   474→ * Calculate confidence percentage based on score and number of matches
   475→ */
   476→function calculateConfidence(score: number, numMatches: number): number {
   477→  if (score === 0) return 0;
   478→
   479→  // Basic confidence calculation: higher scores and more matches = higher confidence
   480→  // Cap at 95% to leave room for AI enhancement
   481→  const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
   482→  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%
   483→
   484→  return Math.min(baseConfidence + matchBonus, 95);
   485→}
   486→
   487→/**
   488→ * Select the best subtype based on scores
   489→ */
   490→function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
   491→  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
   492→    return null;
   493→  }
   494→
   495→  // Find subtype with highest score
   496→  let bestSubtype: string | null = null;
   497→  let bestScore = -1;
   498→
   499→  for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
   500→    const score = scoreData?.totalScore || 0;
   501→    if (score > bestScore) {
   502→      bestScore = score;
   503→      bestSubtype = subtypeId;
   504→    }
   505→  }
   506→
   507→  return bestScore > 0 ? bestSubtype : null;
   508→}
